import { Flex, Skeleton, Switch, SwitchProps, Text, TextProps } from '@chakra-ui/react';
import { forwardRef, ReactNode } from 'react';
import { BaseProps } from '../baseProps';
import { FormControl } from '../FormControl';

export type ISwitchControlProps = BaseProps &
  Overwrite<SwitchProps, { value?: number | string | boolean }> & {
    boldTitle?: boolean;
    direction?: 'right' | 'left';
    formHelperText?: ReactNode;
    formLabel?: string;
    formLabelProps?: TextProps;
    formTitle?: string;
    isLoading?: boolean;
    spaceBetween?: boolean;
  };

export const SwitchControl = forwardRef<HTMLInputElement, ISwitchControlProps>((props, ref) => {
  const {
    boldTitle = true,
    direction = 'right',
    formControlProps,
    formHelperText,
    formLabel,
    formLabelProps,
    formTitle,
    isInvalid,
    isLoading,
    isRequired,
    label,
    name,
    spaceBetween,
    testid,
    value,
    ...rest
  } = props;

  const switchComponent = (
    <Flex
      justifyContent={spaceBetween ? 'flex-end' : 'flex-start'}
      p={2}
      w={spaceBetween ? undefined : '50%'}
    >
      <Skeleton isLoaded={!isLoading} lineHeight="1">
        <Switch {...rest} id={name} isChecked={!!value} name={name} ref={ref} />
      </Skeleton>
    </Flex>
  );

  return (
    <FormControl
      data-testid={testid}
      formHelperText={formHelperText}
      isInvalid={isInvalid}
      isRequired={isRequired}
      label={label}
      name={name}
      {...formControlProps}
    >
      <Flex align="center" gap={2}>
        {direction === 'left' && switchComponent}
        {(formLabel || formTitle) && (
          <Flex
            direction="column"
            flexGrow={spaceBetween ? 1 : undefined}
            gap={2}
            sx={{ '*': { color: rest.isDisabled ? 'neutral.600' : undefined } }}
            w={spaceBetween ? undefined : '50%'}
          >
            {formTitle && (
              <Text
                as="label"
                htmlFor={!formLabel ? name : undefined}
                textStyle={boldTitle ? 'labelBold' : 'labelMedium'}
              >
                {formTitle}
              </Text>
            )}
            {formLabel && (
              <Text as="label" htmlFor={name} textStyle="metaRegular" {...formLabelProps}>
                {formLabel}
              </Text>
            )}
          </Flex>
        )}
        {direction === 'right' && switchComponent}
      </Flex>
    </FormControl>
  );
});

